import{_ as a,o as s,c as t,a0 as i}from"./chunks/framework.CEW4uG-d.js";const u=JSON.parse('{"title":"Router Setup (OpenWrt)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/router-setup.md","filePath":"guide/router-setup.md"}'),n={name:"guide/router-setup.md"};function o(r,e,l,p,d,h){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="router-setup-openwrt" tabindex="-1">Router Setup (OpenWrt) <a class="header-anchor" href="#router-setup-openwrt" aria-label="Permalink to &quot;Router Setup (OpenWrt)&quot;">​</a></h1><p>BlockGuard is written in optimized Go, meaning it can be compiled into a single static binary for any CPU architecture (including <strong>ARM</strong> or <strong>MIPS/MIPSEL</strong> commonly used in routers).</p><p>By running BlockGuard directly on your router, you get network-wide ad blocking:</p><ul><li><strong>Zero device resource usage:</strong> Laptops and mobile phones do not run any local agent, saving battery and CPU.</li><li><strong>Universal coverage:</strong> All connected devices (Smart TVs, iPads, gaming consoles, guests&#39; phones) are automatically protected.</li></ul><hr><h2 id="step-1-download-the-router-binary" tabindex="-1">Step 1: Download the Router Binary <a class="header-anchor" href="#step-1-download-the-router-binary" aria-label="Permalink to &quot;Step 1: Download the Router Binary&quot;">​</a></h2><p>Download the compiled archive matching your router&#39;s processor from the <a href="https://github.com/PrathxmOp/BlockGuard/releases" target="_blank" rel="noreferrer">GitHub Releases Page</a>:</p><ul><li>Modern/Premium routers (ARM-based) → <code>blockguard-VERSION-router-arm.tar.gz</code></li><li>Budget/Legacy routers (MIPS-based) → <code>blockguard-VERSION-router-mips.tar.gz</code></li></ul><p>Extract the archive locally to get the <code>blockguard</code> executable.</p><hr><h2 id="step-2-upload-blockguard-to-the-router" tabindex="-1">Step 2: Upload BlockGuard to the Router <a class="header-anchor" href="#step-2-upload-blockguard-to-the-router" aria-label="Permalink to &quot;Step 2: Upload BlockGuard to the Router&quot;">​</a></h2><p>Use SCP (Secure Copy) from your terminal to transfer the binary to the router&#39;s <code>/usr/bin/</code> folder:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Transfer the binary</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.1.1:/usr/bin/blockguard</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># SSH into the router</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.1.1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Make the binary executable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/blockguard</span></span></code></pre></div><p><em>(Replace <code>192.168.1.1</code> with your router&#39;s gateway IP address).</em></p><hr><h2 id="step-3-run-blockguard-on-a-custom-port" tabindex="-1">Step 3: Run BlockGuard on a Custom Port <a class="header-anchor" href="#step-3-run-blockguard-on-a-custom-port" aria-label="Permalink to &quot;Step 3: Run BlockGuard on a Custom Port&quot;">​</a></h2><p>By default, routers run their own DNS resolver (e.g. <code>dnsmasq</code> or <code>unbound</code>) on port <code>53</code>. BlockGuard cannot bind to port 53 directly.</p><p>Instead, we configure BlockGuard to run on <strong>port 5353</strong> listening on the local loopback interface:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set configuration options on the router</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns.listen_address</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns.listen_port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5353</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start the BlockGuard daemon</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><hr><h2 id="step-4-configure-dns-forwarding-openwrt" tabindex="-1">Step 4: Configure DNS Forwarding (OpenWrt) <a class="header-anchor" href="#step-4-configure-dns-forwarding-openwrt" aria-label="Permalink to &quot;Step 4: Configure DNS Forwarding (OpenWrt)&quot;">​</a></h2><p>We now configure the router&#39;s main DNS resolver to forward all external lookup queries to BlockGuard running on port 5353.</p><h3 id="method-a-via-web-gui-luci" tabindex="-1">Method A: Via Web GUI (LuCI) <a class="header-anchor" href="#method-a-via-web-gui-luci" aria-label="Permalink to &quot;Method A: Via Web GUI (LuCI)&quot;">​</a></h3><ol><li>Open the OpenWrt Web Interface, and go to <strong>Network</strong> → <strong>DHCP and DNS</strong>.</li><li>Locate the <strong>DNS Forwardings</strong> text box.</li><li>Add the address pointing to BlockGuard:<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>127.0.0.1#5353</span></span></code></pre></div><em>(Note: OpenWrt uses <code>#</code> instead of <code>:</code> to specify port numbers in DNS configurations).</em></li><li>Click <strong>Save &amp; Apply</strong>.</li></ol><h3 id="method-b-via-cli-config" tabindex="-1">Method B: Via CLI Config <a class="header-anchor" href="#method-b-via-cli-config" aria-label="Permalink to &quot;Method B: Via CLI Config&quot;">​</a></h3><p>Open <code>/etc/config/dhcp</code> on the router:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/config/dhcp</span></span></code></pre></div><p>Find the <code>config dnsmasq</code> block and add the server option:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>list server &#39;127.0.0.1#5353&#39;</span></span></code></pre></div><p>Save and exit (<code>:wq</code>), then restart the <code>dnsmasq</code> service:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/init.d/dnsmasq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div><hr><h2 id="🎉-verification" tabindex="-1">🎉 Verification <a class="header-anchor" href="#🎉-verification" aria-label="Permalink to &quot;🎉 Verification&quot;">​</a></h2><p>Connect a device to your Wi-Fi, open any webpage, and then run the status command on the router terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>You should see queries counting up and ad/tracker domains being successfully intercepted. Your whole home network is now protected!</p>`,36)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
